import { createSubgraph } from "../../subgraph.js";
import { products } from "./data.js";

export default createSubgraph("link", {
  typeDefs: /* GraphQL */ `
    extend schema
      @link(url: "https://specs.apollo.dev/federation/v2.0", import: ["@key"])

    type Product @key(fields: "id") @key(fields: "id pid") {
      id: String!
      pid: String!
    }
  `,
  resolvers: {
    Product: {
      __resolveReference(
        key:
          | {
              id: string;
              pid: string;
            }
          | {
              id: string;
            },
      ) {
        if ("pid" in key) {
          return products.find(
            (product) => product.id === key.id && product.pid === key.pid,
          );
        }

        return products.find((product) => product.id === key.id);
      },
    },
  },
});

import { createSubgraph } from "../../subgraph.js";
import { products } from "./data.js";

export default createSubgraph("list", {
  typeDefs: /* GraphQL */ `
    extend schema
      @link(
        url: "https://specs.apollo.dev/federation/v2.0"
        import: ["@key", "@shareable"]
      )

    type ProductList @key(fields: "products{id pid}") {
      products: [Product!]!
      first: Product @shareable
      selected: Product @shareable
    }

    type Product @key(fields: "id pid") {
      id: String!
      pid: String
    }
  `,
  resolvers: {
    ProductList: {
      __resolveReference(key: { products: { id: string; pid: string }[] }) {
        const prods = products.filter((p) =>
          key.products.some((k) => k.id === p.id && k.pid === p.pid),
        );
        return {
          products: prods,
          first: prods[0],
          selected: prods[1],
        };
      },
    },
    Product: {
      __resolveReference(key: { id: string; pid: string }) {
        return products.find(
          (product) => product.id === key.id && product.pid === key.pid,
        );
      },
    },
  },
});

import { createSubgraph } from "../../subgraph.js";
import { categories, products } from "./data.js";

export default createSubgraph("price", {
  typeDefs: /* GraphQL */ `
    extend schema
      @link(
        url: "https://specs.apollo.dev/federation/v2.0"
        import: ["@key", "@shareable"]
      )

    type ProductList
      @key(fields: "products{id pid category{id tag}} selected{id}") {
      products: [Product!]!
      first: Product @shareable
      selected: Product @shareable
    }

    type Product @key(fields: "id pid category{id tag}") {
      id: String!
      price: Price
      pid: String
      category: Category
    }

    type Category @key(fields: "id tag") {
      id: String!
      tag: String
    }

    type Price {
      price: Float!
    }
  `,
  resolvers: {
    Product: {
      __resolveReference(key: {
        id: string;
        pid: string;
        category: { id: string; tag: string };
      }) {
        return products.find((p) => {
          if (p.id === key.id && p.pid === key.pid) {
            const cat = categories.find((c) => c.id === p.categoryId);

            if (
              cat &&
              cat.id === key.category.id &&
              cat.tag === key.category.tag
            ) {
              return true;
            }
          }

          return false;
        });
      },
      price(product: (typeof products)[number]) {
        return {
          price: product.price,
        };
      },
      category(product: (typeof products)[number]) {
        return categories.find((c) => c.id === product.categoryId);
      },
    },
    Category: {
      __resolveReference(key: { id: string; tag: string }) {
        return categories.find((c) => c.id === key.id);
      },
    },
    ProductList: {
      __resolveReference(key: {
        products: {
          id: string;
          pid: string;
          category: { id: string; tag: string };
        }[];
        selected: { id: string };
      }) {
        const prods = products.filter((p) =>
          key.products.some((k) => {
            if (p.id === k.id && p.pid === k.pid) {
              const cat = categories.find((c) => c.id === p.categoryId);

              if (
                cat &&
                cat.id === k.category.id &&
                cat.tag === k.category.tag
              ) {
                return true;
              }
            }

            return false;
          }),
        );

        return {
          products: prods,
          first: prods[0],
          selected: products.find((p) => p.id === key.selected.id),
        };
      },
    },
  },
});

import { createSubgraph } from "../../subgraph.js";
import { categories, products } from "./data.js";

export default createSubgraph("products", {
  typeDefs: /* GraphQL */ `
    extend schema
      @link(
        url: "https://specs.apollo.dev/federation/v2.0"
        import: ["@key", "@external", "@extends", "@shareable"]
      )

    type Query {
      topProducts: ProductList!
    }

    type ProductList @key(fields: "products{id}") {
      products: [Product!]!
    }

    type Product @extends @key(fields: "id") {
      id: String! @external
      category: Category @shareable
    }

    type Category @key(fields: "id") {
      mainProduct: Product! @shareable
      id: String!
      tag: String @shareable
    }
  `,
  resolvers: {
    Query: {
      topProducts() {
        return {
          products,
        };
      },
    },
    ProductList: {
      __resolveReference(key: { products: { id: string }[] }) {
        return {
          products: products.filter((p) =>
            key.products.some((k) => k.id === p.id),
          ),
        };
      },
    },
    Product: {
      __resolveReference(key: { id: string }) {
        return products.find((product) => product.id === key.id);
      },
      category(product: (typeof products)[number]) {
        return categories.find((c) => c.id === product.categoryId);
      },
    },
    Category: {
      __resolveReference(key: { id: string }) {
        return categories.find((c) => c.id === key.id);
      },
      mainProduct(category: (typeof categories)[number]) {
        return products.find((p) => p.id === category.mainProduct);
      },
    },
  },
});

