      id: ID!
      name: String!
      price: Float!
    }

    type Category @key(fields: "id") {
      id: ID!
    }
  `,
  resolvers: {
    Query: {
      async product(_: {}, { id }: { id: string }) {
        initProducts();
        const product = (await getProducts()).find((p) => p.id === id);

        if (!product) {
          return null;
        }

        return {
          id: product.id,
          name: product.name,
          price: product.price,
        };
      },
