      async multiply(
        _: {},
        args: {
          by: number;
          requestId: string;
        },
      ) {
        return multiplyNumber(args.by, args.requestId);
      },
      async addProduct(
        _: {},
        {
          input,
        }: {
          input: {
            name: string;
            price: number;
          };
        },
      ) {
        return addProduct(input.name, input.price);
      },
      async addCategory(
        _: {},
        {
          name,
          requestId,
        }: {
